solution: class Solution {
public:
    bool checkSubarraySum(vector<int>& nums, int k) {
        int n = nums.size();
        if (n < 2) return false;
        unordered_map<int, int> mp;
        mp[0] = -1;
        int prefix = 0;
        for (int i = 0; i < n; ++i) {
            prefix = (prefix + nums[i]) % k;
            if (mp.count(prefix)) {
                if (i - mp[prefix] >= 2) return true;
            } else {
                mp[prefix] = i;
            }
        }
        return false;
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(min(n, k))
energy implications: LOW
explanation: Uses prefix sums modulo k and a hash map to store the first index of each remainder. If the same remainder appears again at least two indices later, the subarray between them sums to a multiple of k.

